"use strict";parserFactory.register("fanficparadise.com",()=>new FanFicParadiseParser);class FanFicParadiseParser extends Parser{constructor(){super(),this.cache=new FetchCache,this.minimumThrottle=50}async getChapterUrls(e){return[...e.querySelectorAll("li.threadmarkListItem a")].filter(this.isLinkToChapter).map(e=>util.hyperLinkToChapter(e))}isLinkToChapter(e){return!e.querySelector("date")&&!new URL(e.href).pathname.startsWith("/awards/award")}findContent(e){return Parser.findConstrutedContent(e)}extractTitleImpl(e){return e.querySelector("h1.p-title-value")}extractAuthor(e){let t=e.querySelector("a.username");return null===t?super.extractAuthor(e):t.textContent}async fetchChapter(e){let t,r=await this.cache.fetch(e),a=Parser.makeEmptyDocForContent(e),n=new URL(e),s=n.hash.substring(1)||n.href.substring(n.href.lastIndexOf("/")+1);t=""==s?r.querySelector("li.hasThreadmark"):r.querySelector(`li.hasThreadmark[id='${s}']`),this.addTitleToChapter(a,t);let i=t.querySelector(".messageContent article");return util.resolveLazyLoadedImages(i,"img.lazyload"),a.content.appendChild(i),a.dom}addTitleToChapter(e,t){let r=t.querySelector("span.label"),a=e.dom.createElement("h1");a.textContent=r.textContent.trim(),e.content.appendChild(a)}}